const r = $json;
const existing = ["How to Protest a Data Center's Groundwater Permit in Texas","The Rule of Capture, Explained","The Trinity Aquifer Under Threat: data center boom","When the Ground Sinks: data center pumping and subsidence","Is Your Well Water Safe? Contamination Testing","Projecting Data Center Water Usage and Cooling Demands for 2026","Texas Moves to Rein In the Data Center Boom","Data Center Air Pollution in Texas: A Landowner's Guide","Diesel Generators and Neighborhood Air: The Midlothian Question","Crypto Mine vs. Data Center in Texas","Data Center Noise and Texas Nuisance Law","Proving a Data Center Lowered Your Property Value","Is There a Texas Data Center Lawsuit","What to Do If Your Well Runs Dry","Abilene Data Center Water Use","Corsicana Data Center Property Value","Granbury Data Center Noise","Granbury Data Center Water","Midlothian Data Center Water Use","Red Oak Data Center Property Value","Trinity Aquifer water loss in Ellis County"];
const sys = 'You are a staff writer for BigDataDamage.com, a Texas public-interest site that helps rural landowners understand the harms of data centers (water, air, property). Audience: worried, non-expert landowners. Voice: calm, plain, authoritative, specific, never hypey or salesy. OUTPUT: a single Markdown document with YAML frontmatter and NOTHING else (no code fences, no preamble). Frontmatter keys in order: title, excerpt, date, author (Big Data Damage), harm, location (omit if none), seoTitle, seoDescription. RULES: Markdown only; GFM tables allowed; NO raw HTML, NO style or iframe tags, NO inline CSS. To embed a video put a bare YouTube link on its own line. Cite real sources inline as Markdown links, prefer grounded results, use ranges not false precision, never invent statistics, case names, statutes, or quotes. Structure: 2-3 short intro paragraphs, then 3-5 H2 sections, then an H2 Frequently Asked Questions with 4-6 H3 Q&As, then a short closing H2. About 900-1300 words. Add the internal links from the brief using root-relative paths like /damage/water. No tool-attribution footer. This is a YMYL legal-adjacent topic: be accurate and measured, and note when something is general information, not legal advice about a specific property.';
const brief = 'Write a complete article for this brief.
Title: ' + r.title + '
Target keyword: ' + r.keyword + '
Harm: ' + r.harm + '
Location: ' + (r.location || 'none') + '
Internal links to include: ' + (r.internal_links || 'none') + '
Angle/notes: ' + (r.notes || 'none') + '

Do NOT duplicate the angle or core stats of these existing articles: ' + existing.join('; ');
const body = { systemInstruction: { parts: [{ text: sys }] }, contents: [{ role: 'user', parts: [{ text: brief }] }], tools: [{ googleSearch: {} }], generationConfig: { thinkingConfig: { thinkingLevel: 'HIGH' } } };
return [{ json: { body: body, row_number: r.row_number, title: r.title } }];

const parts = $json.candidates && $json.candidates[0] && $json.candidates[0].content && $json.candidates[0].content.parts ? $json.candidates[0].content.parts : [];
let text = parts.map(function(p){ return p.text || ''; }).join('');
text = text.replace(/^```[a-z]*\n?/i, '').replace(/```\s*$/, '').trim();
const m = text.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
if (!m) { throw new Error('No frontmatter found in draft'); }
const fm = m[1]; const bodyText = m[2];
const tt = fm.match(/title:\s*"?(.+?)"?\s*$/m);
const title = tt ? tt[1] : ($('Build Gemini request').item.json.title || 'untitled');
const slug = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 80);
const stripped = bodyText.replace(/^\s*https?:\/\/\S+\s*$/gim, '');
if (/<\/?[a-z][\s\S]*?>/i.test(stripped)) { throw new Error('Raw HTML detected in body'); }
if (bodyText.trim().split(/\s+/).length < 600) { throw new Error('Draft too short'); }
const contentB64 = Buffer.from(text, 'utf8').toString('base64');
return [{ json: { slug: slug, path: 'src/content/articles/' + slug + '.md', title: title, contentB64: contentB64, row_number: $('Build Gemini request').item.json.row_number } }];
